// Bicep resource with explicit API version
resource myVM 'Microsoft.Compute/virtualMachines@2023-03-01' = {
  name: 'web-01'
  location: 'eastus'
  properties: {
    hardwareProfile: {
      vmSize: 'Standard_D2s_v3'
    }
    storageProfile: {
      imageReference: {
        publisher: 'Canonical'
        offer: '0001-com-ubuntu-server-jammy'
        sku: '22_04-lts-gen2'
        version: 'latest'
      }
      osDisk: {
        createOption: 'FromImage'
        managedDisk: {
          storageAccountType: 'Premium_LRS'
        }
      }
    }
    networkProfile: {
      networkInterfaces: [
        {
          id: myNIC.id
        }
      ]
    }
  }
}

// Bicep automatically infers dependencies from property references
// No explicit dependsOn needed here — Bicep sees that myNIC.id is referenced
resource myVNet 'Microsoft.Network/virtualNetworks@2023-04-01' = {
  name: 'myVNet'
  location: 'eastus'
  properties: {
    addressSpace: { addressPrefixes: ['10.0.0.0/16'] }
    subnets: [{ name: 'default', properties: { addressPrefix: '10.0.0.0/24' } }]
  }
}

resource myNIC 'Microsoft.Network/networkInterfaces@2023-04-01' = {
  name: 'myNIC'
  location: 'eastus'
  properties: {
    ipConfigurations: [{
      name: 'ipconfig1'
      properties: {
        subnet: { id: myVNet.properties.subnets[0].id }  // reference infers dependency
        privateIPAllocationMethod: 'Dynamic'
      }
    }]
  }
}

resource myVM 'Microsoft.Compute/virtualMachines@2023-03-01' = {
  name: 'web-01'
  location: 'eastus'
  properties: {
    hardwareProfile: { vmSize: 'Standard_D2s_v3' }
    networkProfile: {
      networkInterfaces: [{ id: myNIC.id }]  // reference infers dependency
    }
    storageProfile: {
      osDisk: { createOption: 'FromImage', managedDisk: { storageAccountType: 'Premium_LRS' } }
      imageReference: {
        publisher: 'Canonical'
        offer: '0001-com-ubuntu-server-jammy'
        sku: '22_04-lts-gen2'
        version: 'latest'
      }
    }
  }
}
